        return r
    r.ok = True
    return r


def remove_countdown_preset(name: str, *, dry_run: bool = False) -> CountdownOp:
    """Delete countdown preset(s) by name (idle ones; running instances are left
    untouched — stop them first)."""
    r = CountdownOp()
    r.dry_run = dry_run
    try:
        _events, timelines, custom_objects, client, counter = fetch_cloud_state()
    except Exception as ex:
        r.error = f"cloud fetch failed: {ex}"
        return r
    now = datetime.now(timezone.utc).astimezone()
    targets = [
        o
        for o in custom_objects.values()
        if o.object_type == COUNTDOWN_OBJECT_TYPE
        and (o.string_value_2 or "") == name
        and (o.string_value_4 or "").lower() != "true"
    ]
    if not targets:
        r.error = f"no idle countdown preset named {name!r}"
        return r
    wires = [delete_custom_object_wire(o.unique_identifier) for o in targets]
    r.custom_object_wires = wires
    r.countdowns = [_to_countdown(o, timelines, now) for o in targets]
    if dry_run:
        r.ok = True
        return r
    err = _commit_mixed(client, counter, custom_object_wires=wires)
    if err:
        r.error = err
        return r
    r.ok = True
    return r

